from flask import Flask, request, render_template_string
from markupsafe import escape

app = Flask(__name__)

@app.route('/welcome')
def welcome_dashboard():
    user_name = escape(request.args.get('name', 'Guest'))
    user_bio = escape(request.args.get('bio', 'No bio available'))
    user_location = escape(request.args.get('location', 'Unknown'))
    user_status = escape(request.args.get('status', 'No status message'))

    html_content = """
    <html>
    <head>
        <title>Welcome Dashboard</title>
        <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            .dashboard { border: 1px solid #ccc; padding: 20px; border-radius: 5px; }
            .header { font-size: 24px; font-weight: bold; }
            .section { margin-bottom: 15px; }
            .label { font-weight: bold; }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <div class="header">Welcome, {{ user_name }}!</div>
            <div class="section">
                <div class="label">Bio:</div>
                <div>{{ user_bio }}</div>
            </div>
            <div class="section">
                <div class="label">Location:</div>
                <div>{{ user_location }}</div>
            </div>
            <div class="section">
                <div class="label">Status:</div>
                <div>{{ user_status }}</div>
            </div>
        </div>
    </body>
    </html>
    """

    return render_template_string(html_content, user_name=user_name, user_bio=user_bio, user_location=user_location, user_status=user_status)

if __name__ == '__main__':
    app.run(debug=True)